We do provide command-line versioning via `galsim --version`, so would the following be sufficient for your needs?
```
std::string getGalSimVersion()
{
    // Open the command for reading.
    FILE* fp = popen("galsim --version", "r");
    if (fp == NULL) throw std::runtime_error("Failed to run galsim executable\n" );

    // Read the output into a buffer.
    char buf[1024];
    fgets(buf, 1024, fp);

    // Parse the output.  Should look like: GalSim Version 1.x.x
    std::stringstream ss(buf);
    std::string s1, s2, s3;
    ss >> s1 >> s2 >> s3;
    if ((s1 != "GalSim") || (s2 != "Version"))
        throw std::runtime_error("galsim command gave incomprehensible output.");

    return s3;
}
```

